// fakeItemService records calls to UpdateContent for test assertions.
type fakeItemService struct {
	updates []item.ContentUpdate
}

func (f *fakeItemService) UpdateContent(_ context.Context, _ uuid.UUID, input item.ContentUpdate) error {
	f.updates = append(f.updates, input)
	return nil
}

